import React from "react";
import { Link } from "react-router-dom";
import "./navbar.css";

function Navbar({ isLoggedIn }) {
  return (
    <nav className="navbar">
      <ul className="nav-list">
        {!isLoggedIn && (
          <>
            <li className="nav-item"><Link to="/">Sign Up</Link></li>
            <li className="nav-item"><Link to="/signin">Sign In</Link></li>
          </>
        )}
        {isLoggedIn && (
          <>
            <li className="nav-item"><Link to="/addcourse">Add Course</Link></li>
            <li className="nav-item"><Link to="/register-course">Register Course</Link></li>
            <li className="nav-item"><button onClick={() => window.location.reload()}>Logout</button></li>
          </>
        )}
      </ul>
    </nav>
  );
}

export default Navbar;
